+/**
+ * Notification log model types for tracking sent notification history.
+ *
+ * Every notification processed by the NotificationService is logged
+ * with delivery status, enabling history queries by recipient, channel,
+ * type, and date range.
+ */
+
+import type { NotificationChannel, NotificationType } from './notification.js';
+
+/**
+ * Delivery status of a notification.
+ */
+export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';
+
+/**
+ * A persisted log entry for a notification that was processed.
+ */
+export interface NotificationLogEntry {
+  id: string;
+  recipient: string;
+  channel: NotificationChannel;
+  type: NotificationType;
+  subject: string;
+  body: string;
+  status: DeliveryStatus;
+  timestamp: Date;
+  metadata?: Record<string, string>;
+  error?: string;
+}
+
+/**
+ * Query options for filtering notification history.
+ * All fields are optional — omitted fields are not filtered on.
+ */
+export interface NotificationLogQuery {
+  recipient?: string;
+  channel?: NotificationChannel;
+  type?: NotificationType;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

