/**
 * Notification log model types for tracking sent notification history.
 *
 * Every notification processed by the NotificationService is logged
 * with delivery status, enabling history queries by recipient, channel,
 * type, and date range.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';

/**
 * A persisted log entry for a notification that was processed.
 */
export interface NotificationLogEntry {
  id: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  timestamp: Date;
  metadata?: Record<string, string>;
  error?: string;
}

/**
 * Query options for filtering notification history.
 * All fields are optional — omitted fields are not filtered on.
 */
export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLogEntry data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, channel, type, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { NotificationLogEntry, DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification-logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: record['id'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
    };

    if (record['metadata']) {
      entry.metadata = JSON.parse(record['metadata'] as string) as Record<string, string>;
    }

    if (record['error']) {
      entry.error = record['error'] as string;
    }

    return entry;
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
    };

    if (entity.metadata) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }

    if (entity.error) {
      record['error'] = entity.error;
    }

    return record;
  }

  /**
   * Find all log entries for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  /**
   * Find all log entries for a specific channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  /**
   * Find all log entries for a specific notification type.
   */
  findByType(type: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  /**
   * Find all log entries with a specific delivery status.
   */
  findByStatus(status: DeliveryStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.status === status);
  }

  /**
   * Find all log entries within a date range (inclusive).
   */
  findByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.findAll(
      (entry) => entry.timestamp >= startDate && entry.timestamp <= endDate,
    );
  }
}

/**
 * Notification history service — logs and queries notification delivery history.
 *
 * Every notification processed by NotificationService (sent, failed, or
 * suppressed) is logged here. Provides query methods for filtering by
 * recipient, channel, type, status, and date range.
 *
 * Depends on:
 * - NotificationLogRepository for persistence
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  NotificationLogEntry,
  NotificationLogQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification delivery attempt.
   */
  async log(
    payload: NotificationPayload,
    status: DeliveryStatus,
    error?: string,
  ): Promise<NotificationLogEntry> {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      subject: payload.subject,
      body: payload.body,
      status,
      timestamp: new Date(),
      metadata: payload.metadata,
      error,
    };

    this.repository.save(entry);
    this.logger.info(`Logged notification ${entry.id}: ${status} (${payload.type} to ${payload.recipient})`);
    return entry;
  }

  /**
   * Query notification history with combined filters.
   * All fields in the query are optional — omitted fields are not filtered on.
   */
  queryHistory(query: NotificationLogQuery): NotificationLogEntry[] {
    return this.repository.findAll((entry) => {
      if (query.recipient && entry.recipient !== query.recipient) return false;
      if (query.channel && entry.channel !== query.channel) return false;
      if (query.type && entry.type !== query.type) return false;
      if (query.status && entry.status !== query.status) return false;
      if (query.startDate && entry.timestamp < query.startDate) return false;
      if (query.endDate && entry.timestamp > query.endDate) return false;
      return true;
    });
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getHistoryForRecipient(recipient: string): NotificationLogEntry[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries for a specific notification type.
   */
  getHistoryByType(type: NotificationLogQuery['type']): NotificationLogEntry[] {
    if (!type) return [];
    return this.repository.findByType(type);
  }

  /**
   * Get all log entries within a date range (inclusive).
   */
  getHistoryByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get the total number of logged notifications.
   */
  getLogCount(): number {
    return this.repository.count();
  }

  /**
   * Get all log entries.
   */
  getAllHistory(): NotificationLogEntry[] {
    return this.repository.findAll();
  }
}

