private async sendNotification(payload: NotificationPayload, userId?: string): Promise<void> {
  // Check user preferences if a preferences service is available
  if (this.preferencesService && userId && payload.channel === 'email') {
    if (!this.preferencesService.shouldSendEmail(userId, payload.type)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${payload.type} to ${payload.recipient}`,
      );
      await this.historyService?.log(payload, 'suppressed');
      return;
    }
  }

  const record: NotificationRecord = {
    id: generateNotificationId(),
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    type: payload.type,
    sentAt: new Date(),
    metadata: payload.metadata,
  };
  this.notifications.push(record);

  const adapter = this.adapters.get(payload.channel);
  if (adapter) {
    try {
      await adapter.send(payload);
      await this.historyService?.log(payload, 'sent');
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(
        `Adapter failed for channel ${payload.channel}: ${errorMessage}`,
      );
      await this.historyService?.log(payload, 'failed', errorMessage);
    }
  } else {
    this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
    await this.historyService?.log(payload, 'sent');
  }

  this.logger.info(`Notification sent: ${record.id} to ${payload.recipient}`);
}

